import{_ as a,c as e,o as i,ah as o}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"claudecodeui","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/claudecodeui-开发工具.md","filePath":"github汇总/开发工具/claudecodeui-开发工具.md"}'),r={name:"github汇总/开发工具/claudecodeui-开发工具.md"};function d(t,l,n,h,c,s){return i(),e("div",null,l[0]||(l[0]=[o('<h1 id="claudecodeui" tabindex="-1">claudecodeui <a class="header-anchor" href="#claudecodeui" aria-label="Permalink to “claudecodeui”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>claudecodeui</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>siteboon</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>开发工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>在终端中使用AI编码工具不够直观，无法方便地浏览文件和管理Git。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>为Claude Code、Codex、Gemini CLI、OpenCode等AI编码工具提供Web界面。支持响应式设计，可在桌面、平板和手机使用。内置交互式聊天界面、集成Shell终端、文件浏览器（支持语法高亮和实时编辑）、Git浏览器（查看、暂存、提交、切换分支）。支持会话管理（恢复对话、管理多个会话、跟踪历史）。提供插件系统扩展功能。支持TaskMaster AI集成进行项目管理。所有工具默认禁用，需手动启用保护安全。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>支持多种AI编码工具（Claude Code、Codex、Gemini CLI、OpenCode）</li><li>响应式设计，支持移动端</li><li>内置文件浏览器和Git管理</li><li>插件系统可扩展</li><li>所有工具默认禁用，保护安全</li><li>支持CloudCLI Cloud云端部署</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/siteboon/claudecodeui" target="_blank" rel="noreferrer">https://github.com/siteboon/claudecodeui</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用CloudCLI UI管理AI编码工具的用户。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><p><strong>检查Node.js版本</strong></p><ul><li>执行命令：<code>node -v</code></li><li>通过标准：显示Node.js v22或更高版本</li></ul></li><li><p><strong>检查Claude Code是否安装</strong>（如需使用Claude Code）</p><ul><li>执行命令：<code>claude --version</code></li><li>通过标准：显示Claude Code版本号</li></ul></li></ol><h3 id="主路径-使用npx快速启动-推荐" tabindex="-1">主路径：使用npx快速启动（推荐） <a class="header-anchor" href="#主路径-使用npx快速启动-推荐" aria-label="Permalink to “主路径：使用npx快速启动（推荐）”">​</a></h3><p><strong>步骤1：运行CloudCLI UI</strong></p><ul><li>目标：使用npx启动服务</li><li>位置：终端</li><li>命令：<code>npx @siteboon/claude-code-ui</code></li><li>成功标志：服务启动，显示访问地址</li><li>失败处理：检查Node.js版本</li></ul><p><strong>步骤2：访问Web界面</strong></p><ul><li>目标：打开Web界面</li><li>位置：浏览器</li><li>操作：访问 <a href="http://localhost:3001" target="_blank" rel="noreferrer">http://localhost:3001</a></li><li>成功标志：Web界面正常显示</li><li>失败处理：检查端口是否被占用</li></ul><h3 id="备选路径-全局安装" tabindex="-1">备选路径：全局安装 <a class="header-anchor" href="#备选路径-全局安装" aria-label="Permalink to “备选路径：全局安装”">​</a></h3><p><strong>步骤1：全局安装</strong></p><ul><li>目标：安装到全局</li><li>位置：终端</li><li>命令：<code>npm install -g @siteboon/claude-code-ui</code></li><li>成功标志：安装成功提示</li><li>失败处理：检查npm权限</li></ul><p><strong>步骤2：启动服务</strong></p><ul><li>目标：运行CloudCLI</li><li>位置：终端</li><li>命令：<code>cloudcli</code></li><li>成功标志：服务启动成功</li><li>失败处理：检查安装是否成功</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>Web界面正常打开</li><li>可以看到已有的会话列表</li><li>文件浏览器可以正常工作</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>端口3001被占用</strong></p><ul><li>可能原因：其他服务占用端口</li><li>解决步骤：关闭占用服务或修改配置端口</li></ul></li><li><p><strong>会话列表为空</strong></p><ul><li>可能原因：没有现有的Claude Code会话</li><li>解决步骤：先在终端中使用Claude Code创建会话</li></ul></li><li><p><strong>工具无法使用</strong></p><ul><li>可能原因：工具默认禁用</li><li>解决步骤：在设置中手动启用需要的工具</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://github.com/siteboon/claudecodeui#documentation" target="_blank" rel="noreferrer">CloudCLI Documentation</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',38)]))}const b=a(r,[["render",d]]);export{p as __pageData,b as default};
